if not REDIS_NODES:
    raise RuntimeError("REDIS_NODES environment variable is required, e.g. host1:6379,host2:6379")

def parse_nodes(nodes: str):
    parsed = []
    for item in nodes.split(","):
        item = item.strip()
        if not item:
            continue
        if ":" in item:
            host, port = item.rsplit(":", 1)
            parsed.append((host.strip(), int(port.strip())))
        else:
            parsed.append((item, 6379))
    if not parsed:
        raise RuntimeError("No valid Redis nodes found in REDIS_NODES")
    return parsed

def build_redis_client():
    startup_nodes = [{"host": host, "port": port} for host, port in parse_nodes(REDIS_NODES)]
    if hasattr(redis, "RedisCluster"):
        return redis.RedisCluster(
            startup_nodes=startup_nodes,
            username=REDIS_USERNAME,
            password=REDIS_PASSWORD,
            ssl=REDIS_TLS,
            socket_timeout=REDIS_SOCKET_TIMEOUT,
            socket_connect_timeout=REDIS_CONNECT_TIMEOUT,
            decode_responses=True,
            health_check_interval=30,
        )
